#!/usr/bin/env python3
"""paris-server.py

OpenAI-compat shim over a running fat-station. Stdlib HTTP + transformers
tokenizer; no node/npm. Tokenizes input via HF Qwen tokenizer, POSTs raw
token IDs to fat-station's /generate, detokenizes the response.

Usage:
  FAT_STATION_URL=http://127.0.0.1:8000 \
  PARIS_PORT=8080 \
  HF_MODEL=Qwen/Qwen2.5-Coder-7B-Instruct \
    python3 paris-server.py

Then:
  curl -s http://localhost:8080/v1/chat/completions \
    -H 'content-type: application/json' \
    -d '{"messages":[{"role":"user","content":"What is the capital of France?"}],"max_tokens":32}'
"""
import json
import os
import sys
import time
import urllib.request
import urllib.error
from http.server import ThreadingHTTPServer, BaseHTTPRequestHandler

FAT_STATION_URL = os.environ.get("FAT_STATION_URL", "http://127.0.0.1:8000")
PARIS_PORT = int(os.environ.get("PARIS_PORT", "8080"))
HF_MODEL = os.environ.get("HF_MODEL", "Qwen/Qwen2.5-Coder-7B-Instruct")
MODEL_ID = os.environ.get("MODEL_ID", "qwen-coder-7b")

print(f"[paris] loading tokenizer: {HF_MODEL}", flush=True)
os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
os.environ.setdefault("OMP_NUM_THREADS", "1")
from transformers import AutoTokenizer
tok = AutoTokenizer.from_pretrained(HF_MODEL)
print(f"[paris] tokenizer ready (vocab={tok.vocab_size})", flush=True)


def render_chat(messages):
    """Apply Qwen2 chat template via HF tokenizer's apply_chat_template."""
    return tok.apply_chat_template(
        messages, tokenize=False, add_generation_prompt=True
    )


def call_fat_station_generate(tokens, max_new_tokens, temperature):
    body = json.dumps({
        "tokens": list(tokens),
        "max_new_tokens": int(max_new_tokens),
        "temperature": float(temperature),
    }).encode("utf-8")
    req = urllib.request.Request(
        f"{FAT_STATION_URL}/generate",
        data=body,
        headers={"content-type": "application/json"},
        method="POST",
    )
    with urllib.request.urlopen(req, timeout=1800) as resp:
        return json.loads(resp.read().decode("utf-8"))


class ParisHandler(BaseHTTPRequestHandler):
    def log_message(self, fmt, *args):
        sys.stderr.write(f"[paris] {fmt % args}\n")

    def _send_json(self, status, payload):
        body = json.dumps(payload).encode("utf-8")
        self.send_response(status)
        self.send_header("content-type", "application/json")
        self.send_header("content-length", str(len(body)))
        self.send_header("access-control-allow-origin", "*")
        self.end_headers()
        self.wfile.write(body)

    def do_GET(self):
        if self.path == "/health":
            self._send_json(200, {"status": "ok", "model": MODEL_ID, "tokenizer": HF_MODEL})
            return
        if self.path == "/v1/models":
            self._send_json(200, {
                "object": "list",
                "data": [{"id": MODEL_ID, "object": "model", "owned_by": "gnosis", "created": 0}],
            })
            return
        self._send_json(404, {"error": "not found"})

    def do_POST(self):
        if self.path not in ("/v1/chat/completions", "/v1/completions"):
            self._send_json(404, {"error": "not found"})
            return
        try:
            n = int(self.headers.get("content-length", "0"))
            raw = self.rfile.read(n)
            body = json.loads(raw.decode("utf-8"))
            messages = body.get("messages") or []
            raw_prompt = body.get("prompt")
            max_new = int(body.get("max_tokens") or body.get("max_new_tokens") or 32)
            temperature = float(body.get("temperature") or 0.0)

            # Raw completion mode (`prompt` field present) bypasses the chat
            # template. Useful for the small-model Paris demo where the
            # multi-step chat-template decode loses coherence after the first
            # token; a plain completion prompt like "The capital of France is"
            # produces the correct " Paris" greedy continuation in one token.
            if raw_prompt is not None:
                prompt = raw_prompt
            else:
                prompt = render_chat(messages)
            prompt_tokens = tok.encode(prompt, add_special_tokens=False)
            sys.stderr.write(f"[paris] prompt_tokens={len(prompt_tokens)} max_new={max_new}\n")

            t0 = time.time()
            fs_resp = call_fat_station_generate(prompt_tokens, max_new, temperature)
            elapsed = time.time() - t0
            gen = fs_resp.get("generated_tokens", [])
            text = tok.decode(gen, skip_special_tokens=True)
            sys.stderr.write(f"[paris] generated {len(gen)} tokens in {elapsed:.2f}s ({(len(gen)/elapsed if elapsed>0 else 0):.2f} tok/s)\n")
            sys.stderr.write(f"[paris] OUTPUT: {text!r}\n")

            self._send_json(200, {
                "id": f"chatcmpl-{int(t0)}",
                "object": "chat.completion",
                "created": int(t0),
                "model": MODEL_ID,
                "choices": [{
                    "index": 0,
                    "message": {"role": "assistant", "content": text},
                    "finish_reason": "stop",
                }],
                "usage": {
                    "prompt_tokens": len(prompt_tokens),
                    "completion_tokens": len(gen),
                    "total_tokens": len(prompt_tokens) + len(gen),
                },
                "_paris": {
                    "elapsed_s": round(elapsed, 3),
                    "tok_per_s": round(len(gen) / elapsed, 3) if elapsed > 0 else 0,
                    "fat_station_elapsed_ms": fs_resp.get("elapsed_ms"),
                },
            })
        except urllib.error.HTTPError as e:
            self._send_json(502, {"error": "fat-station error", "status": e.code, "detail": e.read().decode("utf-8", "replace")[:500]})
        except Exception as e:
            sys.stderr.write(f"[paris] EXC: {type(e).__name__}: {e}\n")
            self._send_json(500, {"error": str(e)})


def main():
    server = ThreadingHTTPServer(("127.0.0.1", PARIS_PORT), ParisHandler)
    print(f"[paris] listening on http://127.0.0.1:{PARIS_PORT}  → {FAT_STATION_URL}", flush=True)
    server.serve_forever()


if __name__ == "__main__":
    main()
